 99→    private fun PostPrepublishingHomeFragmentBinding.initViewModel() {
100→        viewModel = ViewModelProvider(this@PrepublishingHomeFragment, viewModelFactory)
101→            .get(PrepublishingHomeViewModel::class.java)
102→
103→        viewModel.storyTitleUiState.observe(viewLifecycleOwner) { storyTitleUiState ->
104→            uiHelpers.updateVisibility(storyTitleHeaderView, true)
105→            storyTitleHeaderView.init(uiHelpers, imageManager, storyTitleUiState)
106→        }
107→
108→        viewModel.uiState.observe(viewLifecycleOwner) { uiState ->
109→            uiState?.let { (actionsRecyclerView.adapter as PrepublishingHomeAdapter).update(it) }
110→        }
111→
112→        viewModel.onActionClicked.observeEvent(viewLifecycleOwner) { actionType ->
113→            actionClickedListener?.onActionClicked(actionType)
114→        }
115→
116→        viewModel.onSubmitButtonClicked.observeEvent(viewLifecycleOwner) { publishPost ->
117→            actionClickedListener?.onSubmitButtonClicked(publishPost)
118→        }
119→
120→        val isStoryPost = checkNotNull(arguments?.getBoolean(IS_STORY_POST)) {
121→            "arguments can't be null."
122→        }
123→
124→        viewModel.start(getEditPostRepository(), getSite(), isStoryPost)
125→    }
